import{_ as C,o as g,c as B,a0 as E}from"./chunks/framework.RL10UjUE.js";const Q="data:image/png;base64,",Y=JSON.parse('{"title":"重複検出・マージ","description":"","frontmatter":{},"headers":[],"relativePath":"guide/duplicate.md","filePath":"guide/duplicate.md"}'),I={name:"guide/duplicate.md"};function t(e,A,a,w,s,r){return g(),B("div",null,[...A[0]||(A[0]=[E('<h1 id="重複検出・マージ" tabindex="-1">重複検出・マージ <a class="header-anchor" href="#重複検出・マージ" aria-label="Permalink to &quot;重複検出・マージ&quot;">​</a></h1><p>ブックマークが増えてくると、同じ URL を複数回保存してしまうことがあります。本ツールは URL を正規化して重複を検出し、統合（マージ）できます。</p><h2 id="重複スキャン" tabindex="-1">重複スキャン <a class="header-anchor" href="#重複スキャン" aria-label="Permalink to &quot;重複スキャン&quot;">​</a></h2><ol><li>ヘッダーの <strong>重複</strong> ボタンをクリック</li><li>重複グループが一覧表示されます</li><li>各グループでチェックボックスをオンにして、まとめてマージ / スキップを選択</li></ol><p><img src="'+Q+`" alt="重複検出画面"></p><h2 id="url-正規化" tabindex="-1">URL 正規化 <a class="header-anchor" href="#url-正規化" aria-label="Permalink to &quot;URL 正規化&quot;">​</a></h2><p>以下のパラメータを除去してから比較するため、実質的に同じページであれば確実に検出できます。</p><ul><li><code>utm_source</code>, <code>utm_medium</code>, <code>utm_campaign</code>, <code>utm_term</code>, <code>utm_content</code></li><li><code>fbclid</code>, <code>gclid</code>, <code>ref</code>, <code>source</code></li></ul><p>例:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://example.com/page?utm_source=twitter&amp;id=123</span></span>
<span class="line"><span>https://example.com/page?id=123</span></span></code></pre></div><p>→ 両方とも <code>https://example.com/page?id=123</code> として扱われ、重複と判定されます。</p><h2 id="マージ内容" tabindex="-1">マージ内容 <a class="header-anchor" href="#マージ内容" aria-label="Permalink to &quot;マージ内容&quot;">​</a></h2><p>マージを実行すると、次のルールで統合されます。</p><table tabindex="0"><thead><tr><th>項目</th><th>マージルール</th></tr></thead><tbody><tr><td>タイトル</td><td>最も長い空でないタイトルを採用</td></tr><tr><td>タグ</td><td>すべてのタグの和集合</td></tr><tr><td>訪問回数</td><td>合計値</td></tr><tr><td>メモ</td><td>改行で連結</td></tr><tr><td>ソース</td><td>残す方を指定、片方は論理削除</td></tr></tbody></table><p>マージが完了すると、元の重複グループは自動的に閉じられます。</p>`,15)])])}const M=C(I,[["render",t]]);export{Y as __pageData,M as default};
